#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 1e4+5;
const int MOD = 1e4+7;
struct Trie{int fail,son[30];}t[N];
int n,m,Cnt,nc[N],dp[105][N],Ans;
string s[N];
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void BuildTrie(string str){
    int now=0;
    for(char c:str){
        if(!t[now].son[c-'A'])
            t[now].son[c-'A']=(++Cnt);
        now=t[now].son[c-'A'];
    }nc[now]=1;return;
}
void CountFail(){
    queue<int> q;
    while(!q.empty())q.pop();
    t[0].fail=0;
    for(int i=0;i<26;i++)if(t[0].son[i])
        t[t[0].son[i]].fail=0,q.push(t[0].son[i]);
    while(!q.empty()){
        int u=q.front();q.pop();
        for(int i=0;i<26;i++){
            if(t[u].son[i])
                t[t[u].son[i]].fail=t[t[u].fail].son[i],
                nc[t[u].son[i]]|=nc[t[t[u].son[i]].fail],
                q.push(t[u].son[i]);
            else t[u].son[i]=t[t[u].fail].son[i];
        }
    }return;
}
int QP(int x,int y){
    int as=1;
    while(y){
        if(y&1)as=as*x%MOD;
        x=x*x%MOD,y>>=1;
    }return  as;
}
int main(){
    n=read(),m=read();
    for(int i=1;i<=n;i++)
        {cin>>s[i];BuildTrie(s[i]);}
    CountFail();dp[0][0]=1;
    for(int i=0;i<m;i++)for(int u=0;u<=Cnt;u++)
        for(int x=0;x<26;x++)if(!nc[t[u].son[x]])
            dp[i+1][t[u].son[x]]=(dp[i+1][t[u].son[x]]+dp[i][u])%MOD;
    Ans=QP(26,m);
    for(int u=0;u<=Cnt;u++)Ans=(Ans-dp[m][u]+MOD)%MOD;
    cout<<Ans<<"\n";
    return 0;
}
